Here are the public test cases for feature3_1_sigmoid:
{
  "description": "Maps a single-column matrix of real-valued scores to probabilities with the logistic (inverse-logit) function, one probability per row. Scores at or above +10 saturate to 1, scores at or below -10 saturate to 0, and a score of 0 maps to 0.5. Input with more than one column is rejected with a neutral invalid-columns error.",
  "cases": [
    {
      "input": {
        "op": "sigmoid",
        "scores": [
          [
            1.0
          ],
          [
            2.0
          ],
          [
            3.0
          ],
          [
            4.0
          ]
        ]
      },
      "expected_output": "0.731059\n0.880797\n0.952574\n0.982014\n"
    },
    {
      "input": {
        "op": "sigmoid",
        "scores": [
          [
            -1.0
          ],
          [
            -2.0
          ],
          [
            -3.0
          ],
          [
            -4.0
          ]
        ]
      },
      "expected_output": "0.268941\n0.119203\n0.047426\n0.017986\n"
    },
    {
      "input": {
        "op": "sigmoid",
        "scores": [
          [
            50000.0
          ],
          [
            100000.0
          ],
          [
            200.0
          ],
          [
            1000.0
          ],
          [
            10.0
          ]
        ]
      },
      "expected_output": "1\n1\n1\n1\n1\n"
    },
    {
      "input": {
        "op": "sigmoid",
        "scores": [
          [
            -10.0
          ],
          [
            -11.0
          ],
          [
            -12.0
          ],
          [
            -13.0
          ]
        ]
      },
      "expected_output": "0\n0\n0\n0\n"
    }
  ]
}

