Here are the public test cases for feature4_distance_kernels:
{
  "description": "Distance-weighting kernels used to convert a non-negative distance into a similarity weight. Supported kernels: 'uniform' (1/2 inside the unit bandwidth, else 0), 'epanechnikov' (0.75*(1-d^2) inside, else 0), 'cosine' (pi/4*cos(pi/2*d) inside, else 0) and 'gaussian' (standard normal density, unbounded support).",
  "cases": [
    {
      "input": {
        "op": "kernel_weight",
        "kernel": "uniform",
        "distance": 0
      },
      "expected_output": "weight=0.5\n"
    },
    {
      "input": {
        "op": "kernel_weight",
        "kernel": "uniform",
        "distance": 0.5
      },
      "expected_output": "weight=0.5\n"
    },
    {
      "input": {
        "op": "kernel_weight",
        "kernel": "uniform",
        "distance": 1
      },
      "expected_output": "weight=0.5\n"
    },
    {
      "input": {
        "op": "kernel_weight",
        "kernel": "uniform",
        "distance": 1.01
      },
      "expected_output": "weight=0\n"
    },
    {
      "input": {
        "op": "kernel_weight",
        "kernel": "uniform",
        "distance": 10
      },
      "expected_output": "weight=0\n"
    },
    {
      "input": {
        "op": "kernel_weight",
        "kernel": "epanechnikov",
        "distance": 0
      },
      "expected_output": "weight=0.75\n"
    },
    {
      "input": {
        "op": "kernel_weight",
        "kernel": "epanechnikov",
        "distance": 1
      },
      "expected_output": "weight=0\n"
    },
    {
      "input": {
        "op": "kernel_weight",
        "kernel": "epanechnikov",
        "distance": 1.01
      },
      "expected_output": "weight=0\n"
    }
  ]
}

